const TEST_MODE = false;
const TEST_LIMIT = 1;

function clean(value) {
  if (value === undefined || value === null) return '';
  return String(value).trim();
}

function get(row, names) {
  for (const name of names) {
    const value = row[name];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return value;
    }
  }
  return '';
}

function normaliseMoney(value) {
  const raw = clean(value);
  if (!raw) return '';
  return raw.replace(/[$,\s]/g, '');
}

function normalisePsf(value) {
  const raw = clean(value);
  if (!raw) return '';
  return raw.replace(/[$,\s]/g, '');
}

function slug(value) {
  return clean(value)
    .toUpperCase()
    .replace(/\s+/g, ' ')
    .replace(/[^A-Z0-9#\-\/ ]/g, '')
    .trim();
}

function singaporeTimestamp() {
  const now = new Date();
  const singaporeTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Singapore' }));
  const yyyy = singaporeTime.getFullYear();
  const mm = String(singaporeTime.getMonth() + 1).padStart(2, '0');
  const dd = String(singaporeTime.getDate()).padStart(2, '0');
  const hh = String(singaporeTime.getHours()).padStart(2, '0');
  const min = String(singaporeTime.getMinutes()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd} ${hh}:${min}`;
}

const now = singaporeTimestamp();

const sourceSheet = 'Master Listing Sales';
const sourceTab = 'HDB For Sale';
const saleRent = 'Sale';
const propertySegment = 'HDB';

const output = [];

for (const item of items) {
  const row = item.json;

  const clarityRoute = clean(row['Clarity Route']);

  if (!clarityRoute || clarityRoute.toLowerCase() === 'no') {
    continue;
  }

  const projectName = clean(get(row, ['Project Name', 'Project']));
  const blk = clean(get(row, ['Blk', 'Block']));
  const streetName = clean(get(row, ['Street Name', 'Street', 'Address']));
  const level = clean(get(row, ['Level']));
  const unit = clean(get(row, ['Unit', 'Unit No', 'Unit Number']));
  const type = clean(get(row, ['Type', 'Property Type']));
  const size = clean(get(row, ['Size', 'Area', 'Area sqft', 'Size sqft']));
  const noOfBR = clean(get(row, ['No. of BR', 'Bedrooms', 'BR', 'Bedroom Count']));
  const price = normaliseMoney(get(row, ['Price', 'Asking Price', 'Asking Rent', 'Rent', 'Rental']));
  const psf = normalisePsf(get(row, ['PSF', 'Psf', 'psf']));
  const tenure = clean(get(row, ['Tenure', 'Lease']));

  const sourceRowNumber = clean(row.row_number || row.rowNumber || row.__rowNumber || '');

  const sourceKeyParts = [
    sourceSheet,
    sourceTab,
    saleRent,
    propertySegment,
    projectName,
    blk,
    streetName,
    level,
    unit,
    type,
    size,
  ];

  const sourceKey = sourceKeyParts.map(slug).join('|');
  const propertyRecordID = 'PROP-' + Buffer.from(sourceKey).toString('base64url').slice(0, 16).toUpperCase();

  output.push({
    json: {
      'Property Record ID': propertyRecordID,
      'Source Sheet': sourceSheet,
      'Source Tab': sourceTab,
      'Source Row Number': sourceRowNumber,
      'Source Key': sourceKey,
      'Clarity Route': clarityRoute,
      'Sale / Rent': saleRent,
      'Property Segment': propertySegment,
      'Property Subtype': type,
      'Project Name': projectName,
      'Blk': blk,
      'Street Name': streetName,
      'Level': level,
      'Unit': unit,
      'Type': type,
      'Size': size,
      'No. of BR': noOfBR,
      'Price': price,
      'PSF': psf,
      'Tenure': tenure,
      'Automation Eligible': 'Yes',
      'Import Status': 'Synced',
      'First Imported At': now,
      'Last Synced At': now,
      'Sync Notes': `Synced from ${sourceSheet} / ${sourceTab} via Module 1D all-tabs sync`,
    },
  });

  if (TEST_MODE && output.length >= TEST_LIMIT) {
    break;
  }
}

return output;

